const LOGO_SRC = "data:image/png;base64,"

export default function Logo({ size = 36, style = {} }) {
  return (
    <img
      src={LOGO_SRC}
      alt="VEMAR.AI"
      width={size}
      height={size}
      style={{ objectFit: 'contain', borderRadius: size > 50 ? 16 : 6, flexShrink: 0, ...style }}
    />
  )
}
